// ============================================================
//  HELPERS DE AGREGAÇÃO
// ============================================================

const DataEngine = {
    getRaw() { return RAW_DATA; },

    getSemanas() {
        return [...new Set(RAW_DATA.map(d => d.Semana))].sort((a, b) => {
            const [wa, ya] = a.split('.').map(Number);
            const [wb, yb] = b.split('.').map(Number);
            return ya !== yb ? ya - yb : wa - wb;
        });
    },

    getCentros() {
        return [...new Set(RAW_DATA.map(d => d.Cent))].sort();
    },

    getCenTrabs(cent = null) {
        const filtered = cent ? RAW_DATA.filter(d => d.Cent === cent) : RAW_DATA;
        return [...new Set(filtered.map(d => d.CenTrab))].sort();
    },

    agregadoPorCentroSemana() {
        const result = {};
        for (const d of RAW_DATA) {
            if (!result[d.Cent]) result[d.Cent] = {};
            result[d.Cent][d.Semana] = (result[d.Cent][d.Semana] || 0) + (Number(d.tempo) || 0);
        }
        return result;
    },

    // ---------------------------------------------------------
    // CORAÇÃO DA CORREÇÃO: Mapeia a capacidade ÚNICA por CT
    // ---------------------------------------------------------
    capacidadeUnicaMap() {
        const uniqueCaps = {};
        for (const d of RAW_DATA) {
            const cent = d.Cent;
            const sem = d.Semana;
            const ct = String(d.CenTrab).trim(); // Remove espaços que causariam duplicação
            const cap = Number(d.capacidade) || 0;

            if (!uniqueCaps[cent]) uniqueCaps[cent] = {};
            if (!uniqueCaps[cent][sem]) uniqueCaps[cent][sem] = {};
            
            // Defesa absoluta: Pega sempre o MAIOR valor reportado para aquele CT.
            // Ignora linhas repetidas do mesmo CT.
            if (!uniqueCaps[cent][sem][ct] || cap > uniqueCaps[cent][sem][ct]) {
                uniqueCaps[cent][sem][ct] = cap;
            }
        }
        return uniqueCaps;
    },

    capacidadePorCentroSemana() {
        const uniqueCaps = this.capacidadeUnicaMap();
        const result = {};
        for (const cent in uniqueCaps) {
            result[cent] = {};
            for (const sem in uniqueCaps[cent]) {
                result[cent][sem] = Object.values(uniqueCaps[cent][sem]).reduce((a, b) => a + b, 0);
            }
        }
        return result;
    },

    capacidadeTotalPorSemana() {
        const capSemanal = this.capacidadePorCentroSemana();
        const result = {};
        for (const cent in capSemanal) {
            for (const sem in capSemanal[cent]) {
                result[sem] = (result[sem] || 0) + capSemanal[cent][sem];
            }
        }
        return result;
    },

    capacidadeTotalPorCentro() {
        const capSemanal = this.capacidadePorCentroSemana();
        const result = {};
        for (const cent in capSemanal) {
            result[cent] = Object.values(capSemanal[cent]).reduce((a, b) => a + b, 0);
        }
        return result;
    },
    // ---------------------------------------------------------

    agregadoPorCenTrabSemana(cent) {
        const result = {};
        for (const d of RAW_DATA.filter(r => r.Cent === cent)) {
            if (!result[d.CenTrab]) result[d.CenTrab] = {};
            result[d.CenTrab][d.Semana] = (result[d.CenTrab][d.Semana] || 0) + (Number(d.tempo) || 0);
        }
        return result;
    },

    topCenTrabs(cent, n = 5) {
        const totais = {};
        for (const d of RAW_DATA.filter(r => r.Cent === cent)) {
            totais[d.CenTrab] = (totais[d.CenTrab] || 0) + (Number(d.tempo) || 0);
        }
        return Object.entries(totais)
            .sort((a, b) => b[1] - a[1])
            .slice(0, n)
            .map(([ct, total]) => ({ cenTrab: ct, total }));
    },

    totalPorCentro() {
        const result = {};
        for (const d of RAW_DATA) {
            result[d.Cent] = (result[d.Cent] || 0) + (Number(d.tempo) || 0);
        }
        return result;
    },

    variacaoSemanal(cent) {
        const agg = this.agregadoPorCentroSemana()[cent] || {};
        const semanas = this.getSemanas();
        return semanas.map((sem, i) => {
            if (i === 0) return { semana: sem, variacao: null };
            const prev = agg[semanas[i - 1]] || 0;
            const curr = agg[sem] || 0;
            const variacao = prev > 0 ? ((curr - prev) / prev) * 100 : null;
            return { semana: sem, variacao };
        });
    },

    mediaSemanal(cent) {
        const agg = this.agregadoPorCentroSemana()[cent] || {};
        const vals = Object.values(agg);
        return vals.length ? vals.reduce((a, b) => a + b, 0) / vals.length : 0;
    },

    chartDataLineCentro(cent) {
        const semanas = this.getSemanas();
        const agg = this.agregadoPorCentroSemana()[cent] || {};
        return {
            labels: semanas,
            datasets: [{
                label: `Centro ${cent}`,
                data: semanas.map(s => parseFloat((agg[s] || 0).toFixed(2)))
            }]
        };
    },

    chartDataStackedCenTrab(cent, topN = 8) {
        const semanas = this.getSemanas();
        const top = this.topCenTrabs(cent, topN).map(t => t.cenTrab);
        const agg = this.agregadoPorCenTrabSemana(cent);
        return {
            labels: semanas,
            datasets: top.map(ct => ({
                label: ct,
                data: semanas.map(s => parseFloat((agg[ct]?.[s] || 0).toFixed(2)))
            }))
        };
    },

    utilizacaoPorCentroSemana() {
        const tempo = this.agregadoPorCentroSemana();
        const cap = this.capacidadePorCentroSemana();
        const result = {};
        for (const cent of Object.keys(tempo)) {
            result[cent] = {};
            for (const sem of this.getSemanas()) {
                const t = tempo[cent]?.[sem] || 0;
                const c = cap[cent]?.[sem] || 0;
                result[cent][sem] = c > 0 ? parseFloat(((t / c) * 100).toFixed(1)) : null;
            }
        }
        return result;
    }
};

window.DataEngine = DataEngine;